properties.script:
// Poll Bahmni's OpenMRS FHIR2 R4 Encounter endpoint; emit one raw FHIR
// Encounter JSON string per resource. Same polling/idempotency model as the
// Patient channel (full resync on redeploy; conditional upsert downstream).
// Apache HttpClient instead of java.net.URL: on Java 17 the JDK's internal
// HttpURLConnection impl classes aren't exported to Rhino's unnamed module.
var BASE = 'https://192.168.1.230/openmrs/ws/fhir2/R4';
var AUTH = 'Basic ' + java.util.Base64.getEncoder().encodeToString(
    new java.lang.String('superman:Admin123').getBytes('UTF-8'));

function newClient() {
    var sslCtx = org.apache.http.ssl.SSLContexts.custom()
        .loadTrustMaterial(null, new org.apache.http.conn.ssl.TrustStrategy({
            isTrusted: function(chain, authType) { return true; }
        })).build();
    var config = org.apache.http.client.config.RequestConfig.custom()
        .setConnectTimeout(10000).setSocketTimeout(30000).build();
    return org.apache.http.impl.client.HttpClients.custom()
        .setSSLContext(sslCtx)
        .setSSLHostnameVerifier(org.apache.http.conn.ssl.NoopHostnameVerifier.INSTANCE)
        .setDefaultRequestConfig(config)
        .build();
}

function httpGet(client, url) {
    var get = new org.apache.http.client.methods.HttpGet(url);
    get.setHeader('Authorization', AUTH);
    get.setHeader('Accept', 'application/fhir+json');
    var resp = client.execute(get);
    try {
        var status = resp.getStatusLine().getStatusCode();
        var body = String(org.apache.http.util.EntityUtils.toString(resp.getEntity(), 'UTF-8'));
        if (status != 200) {
            throw 'GET ' + url + ' -> HTTP ' + status + ' ' + body.substring(0, 300);
        }
        return body;
    } finally {
        resp.close();
    }
}

var fmt = new java.text.SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss'Z'");
fmt.setTimeZone(java.util.TimeZone.getTimeZone('UTC'));
var pollStart = fmt.format(new java.util.Date());

var since = globalChannelMap.get('encounterLastPoll');
var url = BASE + '/Encounter?_count=100' + (since ? '&_lastUpdated=ge' + since : '');

var messages = new java.util.ArrayList();
var client = newClient();
try {
    var pages = 0;
    while (url && pages < 20) {
        var bundle = JSON.parse(httpGet(client, url));
        var entries = bundle.entry || [];
        for (var i = 0; i < entries.length; i++) {
            messages.add(JSON.stringify(entries[i].resource));
        }
        url = null;
        var links = bundle.link || [];
        for (var j = 0; j < links.length; j++) {
            if (links[j].relation == 'next') { url = links[j].url; }
        }
        pages++;
    }
} finally {
    client.close();
}

globalChannelMap.put('encounterLastPoll', pollStart);
return messages;

// Resolve the subject by identifier (never hardcoded ids), then conditionally
// upsert the Encounter into HAPI keyed on the Bahmni encounter UUID under the
// encounter provenance identifier system.
var BAHMNI = 'https://192.168.1.230/openmrs/ws/fhir2/R4';
var AUTH = 'Basic ' + java.util.Base64.getEncoder().encodeToString(
    new java.lang.String('superman:Admin123').getBytes('UTF-8'));
// Phase 3b.6: write through the HIE OAuth gateway (was hapi-hub direct).
var HAPI = 'http://hie-gateway:8080/fhir';
var PATIENT_SYSTEM = 'https://lab.example/identifiers/bahmni-central';
var ENCOUNTER_SYSTEM = 'https://lab.example/identifiers/bahmni-central/encounter';

// HIE gateway token (fetched once per message; used on the subject-lookup GET
// and the Encounter PUT).
var HIE_TOKEN_URL = 'http://keycloak:8080/realms/rural-health-hie/protocol/openid-connect/token';
var HIE_CLIENT_ID = 'central-hospital-mirth';
function hieToken() {
    var sec = new java.lang.String(java.nio.file.Files.readAllBytes(
        java.nio.file.Paths.get('/opt/connect/keycloak-client-secret.txt')), 'UTF-8').trim();
    var kc = org.apache.http.impl.client.HttpClients.createDefault();
    try {
        var post = new org.apache.http.client.methods.HttpPost(HIE_TOKEN_URL);
        var ps = new java.util.ArrayList();
        ps.add(new org.apache.http.message.BasicNameValuePair('grant_type', 'client_credentials'));
        ps.add(new org.apache.http.message.BasicNameValuePair('client_id', HIE_CLIENT_ID));
        ps.add(new org.apache.http.message.BasicNameValuePair('client_secret', sec));
        post.setEntity(new org.apache.http.client.entity.UrlEncodedFormEntity(ps, 'UTF-8'));
        var r = kc.execute(post);
        try { return JSON.parse(String(org.apache.http.util.EntityUtils.toString(r.getEntity(), 'UTF-8'))).access_token; }
        finally { r.close(); }
    } finally { kc.close(); }
}
var HIE_TOKEN = hieToken();

function newClient(trustAll) {
    var builder = org.apache.http.impl.client.HttpClients.custom()
        .setDefaultRequestConfig(org.apache.http.client.config.RequestConfig.custom()
            .setConnectTimeout(10000).setSocketTimeout(30000).build());
    if (trustAll) {
        builder.setSSLContext(org.apache.http.ssl.SSLContexts.custom()
            .loadTrustMaterial(null, new org.apache.http.conn.ssl.TrustStrategy({
                isTrusted: function(chain, authType) { return true; }
            })).build());
        builder.setSSLHostnameVerifier(org.apache.http.conn.ssl.NoopHostnameVerifier.INSTANCE);
    }
    return builder.build();
}

function execute(client, req, okStatuses) {
    var resp = client.execute(req);
    try {
        var status = resp.getStatusLine().getStatusCode();
        var body = String(org.apache.http.util.EntityUtils.toString(resp.getEntity(), 'UTF-8'));
        if (okStatuses.indexOf(status) < 0) {
            throw req.getMethod() + ' ' + req.getURI() + ' -> HTTP ' + status + ' ' + body.substring(0, 500);
        }
        return body;
    } finally {
        resp.close();
    }
}

function bahmniGet(client, path) {
    var get = new org.apache.http.client.methods.HttpGet(BAHMNI + path);
    get.setHeader('Authorization', AUTH);
    get.setHeader('Accept', 'application/fhir+json');
    return execute(client, get, [200]);
}

var src = JSON.parse(connectorMessage.getRawData());
var encId = src.id;

var subjRef = src.subject && src.subject.reference;
if (!subjRef || subjRef.indexOf('Patient/') != 0) {
    throw 'Encounter ' + encId + ' has no Patient subject reference';
}

// Step 1: Bahmni subject UUID -> Bahmni MRN ("Patient Identifier" type).
var bahmniClient = newClient(true);
var mrn = null;
try {
    var subj = JSON.parse(bahmniGet(bahmniClient, '/' + subjRef));
    var ids = subj.identifier || [];
    for (var i = 0; i < ids.length; i++) {
        var t = ids[i].type;
        if (t && t.text == 'Patient Identifier' && ids[i].use != 'old') {
            mrn = ids[i].value;
        }
    }
} finally {
    bahmniClient.close();
}
if (!mrn) {
    throw 'Bahmni subject ' + subjRef + ' has no "Patient Identifier" - cannot resolve in HIE';
}

function stripElementIds(arr) {
    var out = [];
    for (var i = 0; i < (arr || []).length; i++) {
        var copy = JSON.parse(JSON.stringify(arr[i]));
        delete copy.id;
        out.push(copy);
    }
    return out;
}

var hapiClient = newClient(false);
try {
    // Step 2: MRN -> HAPI Patient id, by identifier search (the resolution
    // ADR 0003 / the kickoff doc require; never a hardcoded id).
    //
    // The subject may not have synced yet: the patient channel polls on its
    // own 60s cycle, and a thrown error here is TERMINAL for the message
    // (Mirth's destination retry does not re-run JavaScript Writer
    // exceptions - found the hard way in 2.5 verification). Wait up to 90s,
    // covering a full patient-channel cycle plus margin, before failing.
    var hapiPatientId = null;
    for (var attempt = 0; attempt < 10 && !hapiPatientId; attempt++) {
        if (attempt > 0) { java.lang.Thread.sleep(10000); }
        var lookup = new org.apache.http.client.methods.HttpGet(HAPI + '/Patient?identifier='
            + encodeURIComponent(PATIENT_SYSTEM + '|' + mrn));
        lookup.setHeader('Accept', 'application/fhir+json');
        lookup.setHeader('Authorization', 'Bearer ' + HIE_TOKEN);
        var found = JSON.parse(execute(hapiClient, lookup, [200]));
        if (found.total && found.total >= 1) {
            hapiPatientId = found.entry[0].resource.id;
        }
    }
    if (!hapiPatientId) {
        throw 'Subject ' + mrn + ' not in HIE after 90s (patient channel down or lagging?)';
    }

    // Minimal clinical envelope: identifier, status, class, type, period,
    // subject. Bahmni-local references (location, participant, partOf visit)
    // are dropped - those targets don't exist in the HIE.
    var target = {
        resourceType: 'Encounter',
        identifier: [{ system: ENCOUNTER_SYSTEM, value: encId }],
        status: src.status,
        'class': src['class'],
        type: stripElementIds(src.type),
        period: src.period,
        subject: { reference: 'Patient/' + hapiPatientId }
    };

    // Step 3: conditional upsert keyed on the encounter provenance identifier.
    var put = new org.apache.http.client.methods.HttpPut(HAPI + '/Encounter?identifier='
        + encodeURIComponent(ENCOUNTER_SYSTEM + '|' + encId));
    put.setHeader('Content-Type', 'application/fhir+json');
    put.setHeader('Authorization', 'Bearer ' + HIE_TOKEN);
    put.setEntity(new org.apache.http.entity.StringEntity(JSON.stringify(target), 'UTF-8'));
    execute(hapiClient, put, [200, 201]);
    return 'upserted encounter ' + encId + ' (subject ' + mrn + ')';
} finally {
    hapiClient.close();
}

channel.postprocessingScript:
// This script executes once after a message has been processed
// Responses returned from here will be stored as "Postprocessor" in the response map
return;

channel.deployScript:
// This script executes once when the channel is deployed
// You only have access to the globalMap and globalChannelMap here to persist data
return;

channel.undeployScript:
// This script executes once when the channel is undeployed
// You only have access to the globalMap and globalChannelMap here to persist data
return;
